class Solution {
public:
    int maximumCostSubstring(string s, string chars, vector<int>& vals) {
        int n = s.length();
        vector<int> char_vals(chars.length(), 0);
        for (int i = 0; i < chars.length(); i++) {
            char_vals[chars[i] - 'a'] = vals[i];
        }
        int max_cost = 0;
        for (int i = 0; i < n; i++) {
            int curr_cost = 0;
            for (int j = 0; j < n; j++) {
                if (s[i] == chars[char_vals[s[i]] - 'a') {
                    curr_cost += vals[char_vals[s[i]] - 'a';
                }
                max_cost = max(max_cost, curr_cost);
            }
        }
        return max_cost;
    }
};
